import { useContext, createContext } from 'react';

import { GridSettings } from '../types/legend-internal.js';

export const LegendGridSettingsContext = createContext<GridSettings>({
  maxItemWidth: 0,
  canFitAllItemsWithoutScrollbar: false,
  hasVirtual: false,
  longestSeries: 0,
  maxColumns: 0,
  maxRows: 0,
  minItemWidth: 0,
});

export const useLegendGridSettings = () =>
  useContext(LegendGridSettingsContext);

LegendGridSettingsContext['displayName'] = 'LegendGridSettingsContext';
